using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class WeeklyPlanMealConfiguration : IEntityTypeConfiguration<WeeklyPlanMeal>{public void Configure(EntityTypeBuilder<WeeklyPlanMeal> builder){builder.ToTable("weekly_plan_meals");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("meal_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.MealType).HasConversion<string>().HasMaxLength(20);builder.Property(e => e.PortionMultiplier).HasColumnType("decimal(4,2)").HasDefaultValue(1.0m);builder.HasOne(e => e.Plan).WithMany(p => p.Meals).HasForeignKey(e => e.PlanId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.Recipe).WithMany().HasForeignKey(e => e.RecipeId);builder.HasIndex(e => new { e.PlanId, e.DayOfWeek, e.MealType, e.SortOrder });}}
